    def validate_saml_response(self, saml_response):
        """Validate SAML response structure and content"""
        try:
            # Decode base64 encoded response
            decoded_response = base64.b64decode(saml_response)
            
            # Parse XML
            root = ET.fromstring(decoded_response)
            
            # Validate response structure
            response_element = root.find(f".//{{{SAML_PROTOCOL_NS}}}Response")
            if response_element is None:
                raise SAMLSecurityError("Invalid SAML response: No Response element found")
                
            # Check if response is valid
            status = response_element.find(f".//{{{SAML_PROTOCOL_NS}}}Status")
            if status is not None:
                status_code = status.find(f".//{{{SAML_PROTOCOL_NS}}}StatusCode")
                if status_code is not None and status_code.get('Value') != 'urn:oasis:names:tc:SAML:2.0:status:Success':
                    raise SAMLSecurityError("SAML response status indicates failure")
                    
            # Validate assertion presence
            assertions = root.findall(f".//{{{SAML_NS}}}Assertion")
            if not assertions:
                raise SAMLSecurityError("No assertions found in SAML response")
                
            return root
            
        except Exception as e:
            logger.error(f"SAML response validation failed: {str(e)}")
            raise SAMLSecurityError(f"Invalid SAML response: {str(e)}")
            
    def extract_user_attributes(self, assertion_element):
        """Extract user attributes from SAML assertion"""
        attributes = {}
        
        # Extract subject (user identifier)
        subject = assertion_element.find(f".//{{{SAML_NS}}}Subject")
        if subject is not None:
            name_id = subject.find(f".//{{{SAML_NS}}}NameID")
            if name_id is not None:
                attributes['user_id'] = name_id.text
                
        # Extract attribute statements
        attribute_statements = assertion_element.findall(f".//{{{SAML_NS}}}AttributeStatement")
        for attr_stmt in attribute_statements:
            attributes_elements = attr_stmt.findall(f".//{{{SAML_NS}}}Attribute")
            for attr in attributes_elements:
                attr_name = attr.get('Name')
                attr_values = attr.findall(f".//{{{SAML_NS}}}AttributeValue")
                if attr_values:
                    if len(attr_values) == 1:
                        attributes[attr_name] = attr_values[0].text
                    else:
                        attributes[attr_name] = [val.text for val in attr_values]
                        
        return attributes
        
    def create_user_session(self, attributes):
        """Create secure user session"""
        session['user_attributes'] = attributes
        session['session_id'] = str(uuid.uuid4())
        session['login_time'] = datetime.now().isoformat()
        session.permanent = True
        
        logger.info(f"User session created for user: {attributes.get('user_id', 'unknown')}")
        
    def validate_assertion(self, assertion_element):
        """Validate assertion signature and time constraints"""
        # Check assertion validity period
        validity_period = assertion_element.find(f".//{{{SAML_NS}}}Conditions")
        if validity_period is not None:
            not_before = validity_period.get('NotBefore')
            not_on_or_after = validity_period.get('NotOnOrAfter')
            
            now = datetime.utcnow()
            
            if not_before:
                not_before_dt = datetime.strptime(not_before, "%Y-%m-%dT%H:%M:%SZ")
                if now < not_before_dt:
                    raise SAMLSecurityError("Assertion not yet valid")
                    
            if not_on_or_after:
                not_on_or_after_dt = datetime.strptime(not_on_or_after, "%Y-%m-%dT%H:%M:%SZ")
                if now >= not_on_or_after_dt:
                    raise SAMLSecurityError("Assertion expired")
                    
        # Check issuer
        issuer = assertion_element.find(f".//{{{SAML_NS}}}Issuer")
        if issuer is not None:
            issuer_value = issuer.text
            if not issuer_value:
                raise SAMLSecurityError("Invalid issuer in assertion")
                
        return True

